final:
module top_module (
    input clk,
    input reset,
    output reg [4:0] q
);

    // Ring counter logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 5'b00001;
        else
            q <= {q[3:0], q[4]};
    end

endmodule
